<?php
namespace App\Services\Security;
use App\Models\{SecurityAuditExport,SecurityAuditExportRetentionJob,User};use Carbon\Carbon;use Illuminate\Support\Collection;use Illuminate\Support\Str;use Illuminate\Validation\ValidationException;
class SecurityAuditExportRetentionJobService{public function getCandidates(?Carbon $cutoff=null):Collection{$cutoff??=now();return SecurityAuditExport::where(fn($q)=>$q->whereDate('retention_until','<=',$cutoff)->orWhereNotNull('archived_at'))->get()->filter(fn($e)=>$this->canDeleteExport($e)['allowed'])->values();}public function createDryRun(User $a,?Carbon $cutoff=null):SecurityAuditExportRetentionJob{$this->permit($a,'admin.security.export_retention_jobs.dry_run');$c=$this->getCandidates($cutoff);$j=SecurityAuditExportRetentionJob::create(['job_number'=>'SER-'.now()->format('Ymd').'-'.Str::upper(Str::random(6)),'status'=>'dry_run_completed','mode'=>'dry_run','export_count'=>$c->count(),'cutoff_date'=>($cutoff??now())->toDateString(),'requested_by_id'=>$a->id,'requested_at'=>now()]);foreach($c as $e)$j->items()->create(['security_audit_export_id'=>$e->id,'status'=>'candidate','reason'=>'Eligible in dry run; no deletion.']);$this->event($j,$a,'dry_run_completed',"{$c->count()} candidate(s); no export deleted.");return $j;}public function approveJob($j,User $a,string $reason){$this->permit($a,'admin.security.export_retention_jobs.approve');if(blank($reason)||$j->requested_by_id===$a->id){$this->event($j,$a,'approval_rejected','Requester cannot approve own job and reason is required.');throw ValidationException::withMessages(['approval'=>'Different approver and reason are required.']);}$j->update(['status'=>'approved','mode'=>'approved_delete','approved_by_id'=>$a->id,'approved_at'=>now(),'approval_reason'=>$reason]);$this->event($j,$a,'approved',$reason);return $j->refresh();}public function executeApprovedJob($j,User $a){$this->permit($a,'admin.security.export_retention_jobs.execute');$reason='Physical audit export deletion is disabled and dry-run-only by policy.';$this->event($j,$a,'execution_blocked',$reason);throw ValidationException::withMessages(['execution'=>$reason]);}public function cancelJob($j,User $a,string $reason){$this->permit($a,'admin.security.export_retention_jobs.cancel');$j->update(['status'=>'cancelled','cancellation_reason'=>$reason]);$this->event($j,$a,'cancelled',$reason);return $j->refresh();}public function canDeleteExport(SecurityAuditExport $e):array{$allowed=$e->archived_at||($e->retention_until?->isPast()??false);return ['allowed'=>(bool)$allowed,'reason'=>$allowed?'Archived or retention date passed.':'Export is not archived and retention date has not passed.'];}private function permit($a,$p){if(!$a->can($p))throw ValidationException::withMessages(['permission'=>'Export retention job permission is required.']);}private function event($j,$a,$t,$d){$j->events()->create(['actor_id'=>$a->id,'event_type'=>$t,'description'=>$d,'created_at'=>now()]);}}
